  1→import { lazy, Suspense, useState, useEffect, useCallback, useMemo, useRef } from 'react';
  2→import { ProjectProvider, useProject } from './ProjectProvider';
  3→import { EditorProvider, useEditor } from './EditorProvider';
  4→import { ClipboardProvider } from './ClipboardProvider';
  5→import SvgCanvas from '@/renderers/SvgCanvas';
  6→import SheetCanvas from '@/renderers/SheetCanvas';
  7→import Toolbar from '@/ui/Toolbar';
  8→import Sidebar from '@/ui/Sidebar';
  9→import PropertiesPanel from '@/ui/PropertiesPanel';
 10→import Modal from '@/ui/Modal';
 11→import { createProject } from '@/domain/models';
 12→import { getDefaultActiveFloorId, getOrderedFloors } from '@/domain/floorModels';
 13→import { saveProject, loadProject, listProjects, deleteProject } from '@/persistence/storage';
 14→import { exportProjectFile, importProjectFile } from '@/persistence/fileTransfer';
 15→import { useAutosave } from '@/persistence/useAutosave';
 16→import { isTypingTarget } from '@/utils/keyboard';
 17→import styles from './App.module.css';
 18→
 19→const ThreePreviewPanel = lazy(() => import('@/three/viewer/ThreePreviewPanel'));
 20→
 21→function EditorShell({
 22→  project,
 23→  handleNew,
 24→  handleSave,
 25→  handleLoadClick,
 26→  isSidebarCollapsed,
 27→  isPropertiesCollapsed,
 28→  onToggleSidebar,
 29→  onToggleProperties,
 30→}) {
 31→  const {
 32→    workspaceMode,
 33→    activeSheetId,
 34→    activeFloorId,
 35→    dispatch: editorDispatch,
 36→  } = useEditor();
 37→
 38→  useEffect(() => {
 39→    const sheets = project.sheets || [];
 40→    if (!sheets.length) {
 41→      if (activeSheetId !== null) {
 42→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
 43→      }
 44→      if (workspaceMode === 'sheet') {
 45→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
 46→      }
 47→      return;
 48→    }
 49→
 50→    if (!activeSheetId || !sheets.some((sheet) => sheet.id === activeSheetId)) {
 51→      editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheets[0].id });
 52→    }
 53→  }, [activeSheetId, editorDispatch, project.sheets, workspaceMode]);
 54→
 55→  return (
 56→    <div
 57→      className={styles.layout}
 58→      style={{
 59→        '--layout-sidebar-width': isSidebarCollapsed ? '0px' : 'var(--sidebar-width)',
 60→        '--layout-properties-width': isPropertiesCollapsed ? '0px' : 'var(--properties-width)',
 61→      }}
 62→    >
 63→      <div className={styles.toolbar}>
 64→        <Toolbar
 65→          onNew={handleNew}
 66→          onSave={handleSave}
 67→          onLoad={handleLoadClick}
 68→          isSidebarCollapsed={isSidebarCollapsed}
 69→          isPropertiesCollapsed={isPropertiesCollapsed}
 70→          onToggleSidebar={onToggleSidebar}
 71→          onToggleProperties={onToggleProperties}
 72→        />
 73→      </div>
 74→      <div className={`${styles.sidebar} ${isSidebarCollapsed ? styles.panelHidden : ''}`}>
 75→        <Sidebar />
 76→      </div>
 77→      <div className={styles.canvas}>
 78→        {workspaceMode === 'sheet' ? (
 79→          <SheetCanvas />
 80→        ) : (
 81→          <div className={styles.modelWorkspace}>
 82→            <div className={styles.primaryCanvas}>
 83→              <SvgCanvas />
 84→            </div>
 85→            <div className={styles.preview}>
 86→              <Suspense fallback={<div className={styles.previewFallback}>Loading 3D preview...</div>}>
 87→                <ThreePreviewPanel
 88→                  project={project}
 89→                  activeFloorId={activeFloorId}
 90→                />
 91→              </Suspense>
 92→            </div>
 93→          </div>
 94→        )}
 95→      </div>
 96→      <div className={`${styles.properties} ${isPropertiesCollapsed ? styles.panelHidden : ''}`}>
 97→        <PropertiesPanel />
 98→      </div>
 99→    </div>
100→  );
101→}
102→
103→function AppInner() {
104→  const { project, isDirty, dispatch } = useProject();
105→  const orderedFloors = useMemo(() => getOrderedFloors(project), [project]);
106→  const availableFloorIds = useMemo(() => orderedFloors.map((floor) => floor.id), [orderedFloors]);
107→  const initialActiveFloorId = getDefaultActiveFloorId(project);
108→  const [showLoadModal, setShowLoadModal] = useState(false);
109→  const [savedProjects, setSavedProjects] = useState([]);
110→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
111→  const [isPropertiesCollapsed, setIsPropertiesCollapsed] = useState(false);
112→  const importInputRef = useRef(null);
113→
114→  useAutosave(project, isDirty, dispatch);
115→
116→  // beforeunload warning
117→  useEffect(() => {
118→    const handler = (e) => {
119→      if (isDirty) {
120→        e.preventDefault();
121→        e.returnValue = '';
122→      }
123→    };
124→    window.addEventListener('beforeunload', handler);
125→    return () => window.removeEventListener('beforeunload', handler);
126→  }, [isDirty]);
127→
128→  const handleNew = useCallback(() => {
129→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
130→    dispatch({ type: 'PROJECT_NEW', project: createProject() });
131→  }, [isDirty, dispatch]);
132→
133→  const handleSave = useCallback(async () => {
134→    try {
135→      exportProjectFile(project);
136→      try {
137→        await saveProject(project);
138→      } catch {
139→        // Browser draft sync is secondary to file save.
140→      }
141→      dispatch({ type: 'MARK_SAVED' });
142→    } catch (err) {
143→      alert('Failed to save project file: ' + err.message);
144→    }
145→  }, [project, dispatch]);
146→
147→  // Ctrl+S save
148→  useEffect(() => {
149→    const handler = (e) => {
150→      if (isTypingTarget(e.target)) return;
151→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
152→        e.preventDefault();
153→        handleSave();
154→      }
155→    };
156→    window.addEventListener('keydown', handler);
157→    return () => window.removeEventListener('keydown', handler);
158→  }, [handleSave]);
159→
160→  const handleLoadClick = useCallback(async () => {
161→    setSavedProjects(await listProjects());
162→    setShowLoadModal(true);
163→  }, []);
164→
165→  const handleOpenProjectFile = useCallback(() => {
166→    importInputRef.current?.click();
167→  }, []);
168→
169→  const handleImportFile = useCallback(async (e) => {
170→    const file = e.target.files?.[0] || null;
171→    e.target.value = '';
172→    if (!file) return;
173→
174→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
175→      return;
176→    }
177→
178→    try {
179→      const { project: loaded, savedAt } = await importProjectFile(file);
180→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
181→      setShowLoadModal(false);
182→    } catch (err) {
183→      alert('Failed to import project file: ' + err.message);
184→    }
185→  }, [isDirty, dispatch]);
186→
187→  const handleLoad = useCallback(async (id) => {
188→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
189→    try {
190→      const { project: loaded, savedAt } = await loadProject(id);
191→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
192→      setShowLoadModal(false);
193→    } catch (err) {
194→      alert('Failed to load project: ' + err.message);
195→    }
196→  }, [isDirty, dispatch]);
197→
198→  const handleDelete = useCallback(async (id, name) => {
199→    const confirmed = window.confirm(`Delete "${name}"? This cannot be undone.`);
200→    if (!confirmed) return;
201→
202→    try {
203→      await deleteProject(id);
204→      setSavedProjects(projects => projects.filter(project => project.id !== id));
205→    } catch (err) {
206→      alert('Failed to delete project: ' + err.message);
207→    }
208→  }, []);
209→
210→  return (
211→    <EditorProvider
212→      initialActiveFloorId={initialActiveFloorId}
213→      availableFloorIds={availableFloorIds}
214→    >
215→      <input
216→        ref={importInputRef}
217→        type="file"
218→        accept=".json,application/json"
219→        onChange={handleImportFile}
220→        style={{ display: 'none' }}
221→      />
222→
223→      <EditorShell
224→        project={project}
225→        handleNew={handleNew}
226→        handleSave={handleSave}
227→        handleLoadClick={handleLoadClick}
228→        isSidebarCollapsed={isSidebarCollapsed}
229→        isPropertiesCollapsed={isPropertiesCollapsed}
230→        onToggleSidebar={() => setIsSidebarCollapsed(value => !value)}
231→        onToggleProperties={() => setIsPropertiesCollapsed(value => !value)}
232→      />
233→
234→      {showLoadModal && (
235→        <Modal title="Open Project" onClose={() => setShowLoadModal(false)}>
236→          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
237→            <div
238→              style={{
239→                display: 'flex',
240→                flexDirection: 'column',
241→                gap: '10px',
242→                padding: '12px',
243→                border: '1px solid var(--color-border)',
244→                borderRadius: 'var(--radius-md)',
245→                background: 'var(--color-surface-elevated)',
246→              }}
247→            >
248→              <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
249→                <span style={{ fontSize: '13px', fontWeight: 600 }}>Project File</span>
250→                <span style={{ color: 'var(--color-text-secondary)', fontSize: '12px', lineHeight: 1.4 }}>
251→                  Open a JSON file previously saved to your computer.
252→                </span>
253→              </div>
254→              <button
255→                onClick={handleOpenProjectFile}
256→                style={{
257→                  alignSelf: 'flex-start',
258→                  padding: '8px 14px',
259→                  border: '1px solid var(--color-border)',
260→                  borderRadius: 'var(--radius-sm)',
261→                  cursor: 'pointer',
262→                  fontSize: '12px',
263→                  fontWeight: 600,
264→                  background: 'var(--color-surface-elevated)',
265→                }}
266→              >
267→                Open Project File
268→              </button>
269→            </div>
270→
271→            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
272→              <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
273→                <span style={{ fontSize: '13px', fontWeight: 600 }}>Browser Drafts</span>
274→                <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
275→                  Stored only in this browser on this machine.
276→                </span>
277→              </div>
278→              {savedProjects.length === 0 ? (
279→                <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px', margin: 0 }}>
280→                  No browser drafts found.
281→                </p>
282→              ) : (
283→                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
284→                  {savedProjects.map(p => (
285→                    <div
286→                      key={p.id}
287→                      style={{
288→                        display: 'flex',
289→                        justifyContent: 'space-between',
290→                        alignItems: 'center',
291→                        padding: '10px 12px',
292→                        border: '1px solid var(--color-border)',
293→                        borderRadius: 'var(--radius-md)',
294→                        background: 'var(--color-surface-elevated)',
295→                        fontSize: '13px',
296→                      }}
297→                    >
298→                      <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
299→                        <span style={{ fontWeight: 500 }}>{p.name}</span>
300→                        <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
301→                          {new Date(p.savedAt).toLocaleDateString()}
302→                        </span>
303→                      </div>
304→                      <div style={{ display: 'flex', gap: '8px' }}>
305→                        <button
306→                          onClick={() => handleLoad(p.id)}
307→                          style={{
308→                            padding: '6px 12px',
309→                            border: '1px solid var(--color-border)',
310→                            borderRadius: 'var(--radius-sm)',
311→                            cursor: 'pointer',
312→                            background: 'var(--color-surface-elevated)',
313→                            fontSize: '12px',
314→                            fontWeight: 500,
315→                          }}
316→                        >
317→                          Load
318→                        </button>
319→                        <button
320→                          onClick={() => handleDelete(p.id, p.name)}
321→                          style={{
322→                            padding: '6px 12px',
323→                            border: '1px solid var(--color-danger-subtle)',
324→                            borderRadius: 'var(--radius-sm)',
325→                            cursor: 'pointer',
326→                            background: 'var(--color-danger-subtle)',
327→                            color: 'var(--color-danger)',
328→                            fontSize: '12px',
329→                          }}
330→                        >
331→                          Delete
332→                        </button>
333→                      </div>
334→                    </div>
335→                  ))}
336→                </div>
337→              )}
338→            </div>
339→          </div>
340→          <button
341→            onClick={() => setShowLoadModal(false)}
342→            style={{
343→              marginTop: '16px',
344→              padding: '8px 16px',
345→              border: '1px solid var(--color-border)',
346→              borderRadius: 'var(--radius-sm)',
347→              cursor: 'pointer',
348→              fontSize: '13px',
349→              fontWeight: 500,
350→              background: 'var(--color-surface-elevated)',
351→            }}
352→          >
353→            Cancel
354→          </button>
355→        </Modal>
356→      )}
357→    </EditorProvider>
358→  );
359→}
360→
361→export default function App() {
362→  return (
363→    <ProjectProvider>
364→      <ClipboardProvider>
365→        <AppInner />
366→      </ClipboardProvider>
367→    </ProjectProvider>
368→  );
369→}
