 34→export default function Sidebar() {
 35→  const { project, dispatch, duplicateFloor } = useProject();
 36→  const { activeFloorId, activeSheetId, selectedId, workspaceMode, dispatch: editorDispatch } = useEditor();
 37→  const orderedFloors = getOrderedFloors(project);
 38→  const floor = orderedFloors.find((entry) => entry.id === activeFloorId) || null;
 39→  const [collapsedSections, setCollapsedSections] = useState({
 40→    floors: false,
 41→    sheets: false,
 42→    slabs: false,
 43→    walls: false,
 44→    annotations: false,
 45→    beams: false,
 46→    stairs: false,
 47→    landings: false,
 48→    doors: false,
 49→    windows: false,
 50→    columns: false,
 51→    rooms: false,
 52→  });
 53→
 54→  const selectObject = (id, type) => {
 55→    editorDispatch({ type: 'SELECT_OBJECT', id, objectType: type });
 56→  };
 57→
 58→  const selectFloor = (floorId) => {
 59→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
 60→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
 61→    editorDispatch({ type: 'SELECT_OBJECT', id: floorId, objectType: 'floor' });
 62→  };
 63→
 64→  const setActiveFloor = (floorId) => {
 65→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
 66→  };
 67→
 68→  const addFloor = () => {
 69→    const nextFloor = createFloorAboveHighest(project.floors || []);
 70→    dispatch({ type: 'FLOOR_ADD', floor: nextFloor });
 71→    selectFloor(nextFloor.id);
 72→  };
 73→
 74→  const handleDuplicateFloor = (floorToDuplicate) => {
 75→    const duplicatedFloor = duplicateFloor(floorToDuplicate.id);
 76→    if (!duplicatedFloor) return;
 77→
 78→    dispatch({ type: 'FLOOR_DUPLICATE', floor: duplicatedFloor });
 79→    selectFloor(duplicatedFloor.id);
 80→  };
 81→
 82→  const handleDeleteFloor = (floorToDelete) => {
 83→    if ((project.floors || []).length <= 1) return;
 84→
 85→    const confirmed = window.confirm(`Delete "${floorToDelete.name}"?`);
 86→    if (!confirmed) return;
 87→
 88→    const remainingFloors = orderedFloors.filter((entry) => entry.id !== floorToDelete.id);
 89→    const fallbackFloor = remainingFloors[0] || null;
 90→
 91→    dispatch({
 92→      type: 'FLOOR_DELETE',
 93→      floorId: floorToDelete.id,
 94→      fallbackFloorId: fallbackFloor?.id ?? null,
 95→    });
 96→
 97→    if (floorToDelete.id === activeFloorId && fallbackFloor) {
 98→      if (workspaceMode === 'model') {
 99→        selectFloor(fallbackFloor.id);
100→      } else {
101→        setActiveFloor(fallbackFloor.id);
102→      }
103→    }
104→  };
105→
106→  const addSheet = () => {
